  /**
   * Content-signal STAFF annotations: PII/doxxing (pii-redaction.ts), QR-bait
   * phrasing (qr-bait.ts) and shortener/unseen-domain quarantine
   * (shortener-quarantine.ts). Pure read-only reporting: never deletes,
   * mutes, warns or replies, and never touches the message. When any
   * detector fires, this appends a short annotation to the audit log via
   * `this.repository.recordAudit` (the same audit trail every other ambient
   * detector already writes to) so STAFF can see it in moderation history —
   * group members see nothing. Always returns null. Skips admin authors, same
   * as the neighboring handlePrivacyLeakAmbient/handleScamSignalsAmbient, to
   * keep signal-to-noise low; remove that check if STAFF wants admin content
   * flagged too.
   */
  private async handleContentSignalsAnnotation(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    if (
      update.kind !== "message" ||
      update.command ||
      !update.messageText ||
      !context.chatId ||
      !update.chat.chatId ||
      !update.messageId
    ) {
      return null;
    }

    if (await this.isActorAdmin(context, update)) {
      return null;
    }

    const text = update.messageText;
    const signals: string[] = [];

    // 1) PII / doxxing risk (emails, phones, IBAN, credentialed URLs).
    const pii = detectPii(text);
    const piiCount =
      pii.emails.length +
      pii.phones.length +
      pii.ibans.length +
      pii.urlsWithCreds.length;
    if (piiCount > 0) {
      const parts: string[] = [];
      if (pii.emails.length > 0) parts.push(`${pii.emails.length} email(s)`);
      if (pii.phones.length > 0)
        parts.push(`${pii.phones.length} teléfono(s)`);
      if (pii.ibans.length > 0) parts.push(`${pii.ibans.length} IBAN`);
      if (pii.urlsWithCreds.length > 0)
        parts.push(`${pii.urlsWithCreds.length} URL con credenciales`);
      const doxxing = hasDoxxingRisk(text);
      signals.push(
        `PII detectada (${parts.join(", ")})${doxxing ? " — riesgo de doxxing" : ""}`,
      );
    }

    // 2) QR-bait phrasing ("escanea el QR de pago", ...).
    const qrBait = detectQrBait(text);
    if (qrBait.present) {
      signals.push(`Gancho de QR sospechoso: "${qrBait.detail}"`);
    }

    // 3) Shortener / unseen-domain quarantine, per distinct link domain.
    const domains = BotUpdateService.extractMessageDomains(text);
    for (const domain of domains) {
      const seenBefore = await this.domainReputationRepository.hasSeenDomain(
        context.tenantId,
        domain,
      );
      const shortenerSignal = buildShortenerSignal(domain, seenBefore);
      if (shortenerSignal.present) {
        signals.push(
          `Enlace en cuarentena (${domain}): ${shortenerSignal.detail}`,
        );
      }
      await this.domainReputationRepository.recordDomainSeen(
        context.tenantId,
        domain,
      );
    }

    if (signals.length === 0) {
      return null;
    }

    await this.repository.recordAudit({
      tenantId: context.tenantId,
      actorType: "system",
      action: "content-signal.flagged",
      resourceType: "chat_message",
      resourceId: update.messageId.toString(),
      ...(update.user.userId
        ? { actorId: update.user.userId.toString() }
        : {}),
      payload: {
        chatId: update.chat.chatId.toString(),
        signals,
      },
    });

    return null;
  }

  /**
   * Extracts distinct http(s) link hostnames referenced in `text`. Pure
   * string parsing, no network calls; feeds the shortener/unseen-domain
   * quarantine signal above with a real hostname per link. A URL that fails
   * to parse is silently skipped (nothing to quarantine).
   */
  private static extractMessageDomains(text: string): string[] {
    const matches = text.match(/https?:\/\/[^\s]+/gi) ?? [];
    const domains = new Set<string>();
    for (const match of matches) {
      try {
        domains.add(new URL(match).hostname.toLowerCase());
      } catch {
        // Malformed URL text: skip.
      }
    }
    return [...domains];
  }
